        #region Public Properties
        public PropertyState<EUInformation> EngineeringUnits
        {
            get => m_engineeringUnits;

            set
            {
                if (!Object.ReferenceEquals(m_engineeringUnits, value))
                {
                    ChangeMasks |= NodeStateChangeMasks.Children;
                }

                m_engineeringUnits = value;
            }
        }

        public MultiStateDiscreteState<byte> PhysicalQuantity
        {
            get => m_physicalQuantity;

            set
            {
                if (!Object.ReferenceEquals(m_physicalQuantity, value))
                {
                    ChangeMasks |= NodeStateChangeMasks.Children;
                }

                m_physicalQuantity = value;
            }
        }
        #endregion

        #region Overridden Methods
        public override void GetChildren(
            ISystemContext context,
            IList<BaseInstanceState> children)
        {
            if (m_engineeringUnits != null)
            {
                children.Add(m_engineeringUnits);
            }

            if (m_physicalQuantity != null)
            {
                children.Add(m_physicalQuantity);
            }

            base.GetChildren(context, children);
        }
            
        protected override void RemoveExplicitlyDefinedChild(BaseInstanceState child)
        {
            if (Object.ReferenceEquals(m_engineeringUnits, child))
            {
                m_engineeringUnits = null;
                return;
            }

            if (Object.ReferenceEquals(m_physicalQuantity, child))
            {
                m_physicalQuantity = null;
                return;
            }

            base.RemoveExplicitlyDefinedChild(child);
        }

        protected override BaseInstanceState FindChild(
            ISystemContext context,
            QualifiedName browseName,
            bool createOrReplace,
            BaseInstanceState replacement)
        {
            if (QualifiedName.IsNull(browseName))
            {
                return null;
            }

            BaseInstanceState instance = null;

            switch (browseName.Name)
            {
                case UAModel.IJTBase.BrowseNames.EngineeringUnits:
                {
                    if (createOrReplace)
                    {
                        if (EngineeringUnits == null)
                        {
                            if (replacement == null)
                            {
                                EngineeringUnits = new PropertyState<EUInformation>(this);
                            }
                            else
                            {
                                EngineeringUnits = (PropertyState<EUInformation>)replacement;
                            }
                        }
                    }

                    instance = EngineeringUnits;
                    break;
                }

                case UAModel.IJTBase.BrowseNames.PhysicalQuantity:
                {
                    if (createOrReplace)
                    {
                        if (PhysicalQuantity == null)
                        {
                            if (replacement == null)
                            {
                                PhysicalQuantity = new MultiStateDiscreteState<byte>(this);
                            }
                            else
                            {
                                PhysicalQuantity = (MultiStateDiscreteState<byte>)replacement;
                            }
                        }
                    }

                    instance = PhysicalQuantity;
                    break;
                }
            }

            if (instance != null)
            {
                return instance;
            }

            return base.FindChild(context, browseName, createOrReplace, replacement);
        }
        #endregion

        #region Private Fields
        private PropertyState<EUInformation> m_engineeringUnits;
        private MultiStateDiscreteState<byte> m_physicalQuantity;
        #endregion
    }

