                    if (createOrReplace)
                    {
                        if (EventText == null)
                        {
                            if (replacement == null)
                            {
                                EventText = new BaseDataVariableState<LocalizedText>(this);
                            }
                            else
                            {
                                EventText = (BaseDataVariableState<LocalizedText>)replacement;
                            }
                        }
                    }

                    instance = EventText;
                    break;
                }

                case UAModel.IJTBase.BrowseNames.JoiningTechnology:
                {
                    if (createOrReplace)
                    {
                        if (JoiningTechnology == null)
                        {
                            if (replacement == null)
                            {
                                JoiningTechnology = new BaseDataVariableState<LocalizedText>(this);
                            }
                            else
                            {
                                JoiningTechnology = (BaseDataVariableState<LocalizedText>)replacement;
                            }
                        }
                    }

                    instance = JoiningTechnology;
                    break;
                }

                case UAModel.IJTBase.BrowseNames.ReportedValues:
                {
                    if (createOrReplace)
                    {
                        if (ReportedValues == null)
                        {
                            if (replacement == null)
                            {
