                            {
                                ReportedValues = (BaseDataVariableState<ReportedValueDataType[]>)replacement;
                            }
                        }
                    }

                    instance = ReportedValues;
                    break;
                }
            }

            if (instance != null)
            {
                return instance;
            }

            return base.FindChild(context, browseName, createOrReplace, replacement);
        }
