        public override void GetChildren(
            ISystemContext context,
            IList<BaseInstanceState> children)
        {
            if (m_assetManagement != null)
            {
                children.Add(m_assetManagement);
            }

            if (m_identification != null)
            {
                children.Add(m_identification);
            }

            if (m_joiningProcessManagement != null)
            {
                children.Add(m_joiningProcessManagement);
            }

            if (m_jointManagement != null)
            {
                children.Add(m_jointManagement);
            }

            if (m_machineryBuildingBlocks != null)
            {
                children.Add(m_machineryBuildingBlocks);
            }

            if (m_resultManagement != null)
            {
                children.Add(m_resultManagement);
            }

            base.GetChildren(context, children);
        }
            
        protected override void RemoveExplicitlyDefinedChild(BaseInstanceState child)
        {
            if (Object.ReferenceEquals(m_assetManagement, child))
            {
                m_assetManagement = null;
                return;
            }

            if (Object.ReferenceEquals(m_identification, child))
            {
                m_identification = null;
                return;
            }

            if (Object.ReferenceEquals(m_joiningProcessManagement, child))
            {
                m_joiningProcessManagement = null;
                return;
            }

            if (Object.ReferenceEquals(m_jointManagement, child))
            {
                m_jointManagement = null;
                return;
            }

            if (Object.ReferenceEquals(m_machineryBuildingBlocks, child))
            {
                m_machineryBuildingBlocks = null;
                return;
            }

            if (Object.ReferenceEquals(m_resultManagement, child))
            {
                m_resultManagement = null;
                return;
            }

            base.RemoveExplicitlyDefinedChild(child);
        }

        protected override BaseInstanceState FindChild(
            ISystemContext context,
            QualifiedName browseName,
            bool createOrReplace,
            BaseInstanceState replacement)
        {
            if (QualifiedName.IsNull(browseName))
            {
                return null;
            }

            BaseInstanceState instance = null;

            switch (browseName.Name)
            {
                case UAModel.IJTBase.BrowseNames.AssetManagement:
                {
                    if (createOrReplace)
                    {
                        if (AssetManagement == null)
                        {
                            if (replacement == null)
                            {
                                AssetManagement = new FunctionalGroupTypeState(this);
                            }
                            else
                            {
                                AssetManagement = (FunctionalGroupTypeState)replacement;
                            }
                        }
                    }

                    instance = AssetManagement;
                    break;
                }

                case UAModel.DI.BrowseNames.Identification:
                {
                    if (createOrReplace)
                    {
                        if (Identification == null)
                        {
                            if (replacement == null)
                            {
                                Identification = new JoiningSystemIdentificationTypeState(this);
                            }
                            else
                            {
                                Identification = (JoiningSystemIdentificationTypeState)replacement;
                            }
                        }
                    }

                    instance = Identification;
                    break;
                }

                case UAModel.IJTBase.BrowseNames.JoiningProcessManagement:
                {
                    if (createOrReplace)
                    {
                        if (JoiningProcessManagement == null)
                        {
                            if (replacement == null)
                            {
                                JoiningProcessManagement = new JoiningProcessManagementTypeState(this);
                            }
                            else
                            {
                                JoiningProcessManagement = (JoiningProcessManagementTypeState)replacement;
                            }
                        }
                    }

                    instance = JoiningProcessManagement;
                    break;
                }

                case UAModel.IJTBase.BrowseNames.JointManagement:
                {
                    if (createOrReplace)
                    {
                        if (JointManagement == null)
                        {
                            if (replacement == null)
                            {
                                JointManagement = new JointManagementTypeState(this);
                            }
                            else
                            {
                                JointManagement = (JointManagementTypeState)replacement;
                            }
                        }
                    }

                    instance = JointManagement;
                    break;
                }

                case UAModel.Machinery.BrowseNames.MachineryBuildingBlocks:
                {
                    if (createOrReplace)
                    {
                        if (MachineryBuildingBlocks == null)
                        {
                            if (replacement == null)
                            {
                                MachineryBuildingBlocks = new FolderState(this);
                            }
                            else
                            {
                                MachineryBuildingBlocks = (FolderState)replacement;
                            }
                        }
                    }

                    instance = MachineryBuildingBlocks;
                    break;
                }

                case UAModel.MachineryResult.BrowseNames.ResultManagement:
                {
                    if (createOrReplace)
                    {
                        if (ResultManagement == null)
                        {
                            if (replacement == null)
                            {
                                ResultManagement = new JoiningSystemResultManagementTypeState(this);
                            }
                            else
                            {
                                ResultManagement = (JoiningSystemResultManagementTypeState)replacement;
                            }
                        }
                    }

                    instance = ResultManagement;
                    break;
                }
            }

            if (instance != null)
            {
                return instance;
            }

            return base.FindChild(context, browseName, createOrReplace, replacement);
        }
