        #if (!OPCUA_EXCLUDE_InitializationStrings)
        protected override void Initialize(ISystemContext context)
        {
            base.Initialize(context);
            Initialize(context, InitializationString);
            InitializeOptionalChildren(context);
        }

        protected override void Initialize(ISystemContext context, NodeState source)
        {
            InitializeOptionalChildren(context);
            base.Initialize(context, source);
        }

        protected override void InitializeOptionalChildren(ISystemContext context)
        {
            base.InitializeOptionalChildren(context);

            if (DeleteJoint != null)
            {
                DeleteJoint.Initialize(context, DeleteJoint_InitializationString);
            }

            if (DeleteJointComponent != null)
            {
                DeleteJointComponent.Initialize(context, DeleteJointComponent_InitializationString);
            }

            if (DeleteJointDesign != null)
            {
                DeleteJointDesign.Initialize(context, DeleteJointDesign_InitializationString);
            }

            if (GetJoint != null)
            {
                GetJoint.Initialize(context, GetJoint_InitializationString);
            }

            if (GetJointComponent != null)
            {
                GetJointComponent.Initialize(context, GetJointComponent_InitializationString);
            }

            if (GetJointComponentList != null)
            {
                GetJointComponentList.Initialize(context, GetJointComponentList_InitializationString);
            }

            if (GetJointDesign != null)
            {
                GetJointDesign.Initialize(context, GetJointDesign_InitializationString);
            }

            if (GetJointDesignList != null)
            {
                GetJointDesignList.Initialize(context, GetJointDesignList_InitializationString);
            }

            if (GetJointList != null)
            {
                GetJointList.Initialize(context, GetJointList_InitializationString);
            }

            if (GetJointRevisionList != null)
            {
                GetJointRevisionList.Initialize(context, GetJointRevisionList_InitializationString);
            }

            if (SelectJoint != null)
            {
                SelectJoint.Initialize(context, SelectJoint_InitializationString);
            }

            if (SendJoint != null)
            {
                SendJoint.Initialize(context, SendJoint_InitializationString);
            }

            if (SendJointComponent != null)
            {
                SendJointComponent.Initialize(context, SendJointComponent_InitializationString);
            }

            if (SendJointDesign != null)
            {
                SendJointDesign.Initialize(context, SendJointDesign_InitializationString);
            }
        }

